  "Message": null,
  "Success": true,
  "RefreshItems": [
    {
      "Action": 1,
      "ItemId": "PBT=[item] itm.ID=[c085e8eb-9b69-4163-bf44-28b755e90e4c] itm.DT=[2025-11-13 09:29:04.130]",
      "Properties": [
        {
          "Name": "Item",
          "Value": "{item}" // Dynamic value that should be replaced by the agent based on the item sent.
        },
        {
          "Name": "UM",
          "Value": "EA"
        },
        {
          "Name": "MatlType",
          "Value": "M"
        },
        {
